FROM jsonb_to_recordset('[{"id": "cap-107-society-001", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "塑膠製品進入海洋後易隨著海流漂流，例如有許多塑膠垃圾隨著北大西洋暖\n流漂到北極地區，冰封在冰層中，使得該區成為塑膠垃圾的儲存槽。下列何\n國沿海的垃圾最可能會隨著上述洋流漂流到北極地區？", "options": ["日本", "波蘭", "智利", "挪威"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   塑膠製品進入海洋後易隨著海流漂流，例如有許多塑膠垃圾隨著北大西洋暖\n     流漂到北極地區，冰封在冰層中，使得該區成為塑膠垃圾的儲存槽。下列何\n     國沿海的垃圾最可能會隨著上述洋流漂流到北極地區？\n     (A)日本   (B)波蘭   (C)智利  (D)挪威\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-002", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "為保護臺灣的海岸環境，《海岸管理法》於2015年公布施行，其中濱海陸地\n的劃設是以最接近海岸線的山脊線為主，如果山脊線距離海岸線超過3公里，\n則以最接近海岸線的省道、濱海道路或行政區界等劃設。下列哪一行政區的\n濱海陸地最可能大多依據山脊線劃設？", "options": ["桃園市", "彰化縣 & 山脊線：山脊的連線。", "高雄市", "臺東縣"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   為保護臺灣的海岸環境，《海岸管理法》於2015年公布施行，其中濱海陸地\n     的劃設是以最接近海岸線的山脊線為主，如果山脊線距離海岸線超過3公里，\n     則以最接近海岸線的省道、濱海道路或行政區界等劃設。下列哪一行政區的\n     濱海陸地最可能大多依據山脊線劃設？\n     (A)桃園市          (B)彰化縣\n                              & 山脊線：山脊的連線。\n     (C)高雄市          (D)臺東縣\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-003", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "中國於1970年代末推動的改革開放政策，帶動經濟快速成長，但是卻加深區域發展\n失衡現象。下列關於中國的新聞報導，何者最能反映中國區域發展不均的現象？", "options": ["今年出現的多起沙塵暴，已直接威脅北京、上海及南京等大都市", "推動海上絲路計畫，發展從中國沿海港口經印度洋至歐洲的航線", "農曆春節將湧現數億人次返鄉人潮，堪稱地表最大規模的人口移動", "南方近年降雨減少，旱象環生，南水北調將威脅南方用水的供應量"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   中國於1970年代末推動的改革開放政策，帶動經濟快速成長，但是卻加深區域發展\n     失衡現象。下列關於中國的新聞報導，何者最能反映中國區域發展不均的現象？\n     (A)今年出現的多起沙塵暴，已直接威脅北京、上海及南京等大都市\n     (B)推動海上絲路計畫，發展從中國沿海港口經印度洋至歐洲的航線\n     (C)農曆春節將湧現數億人次返鄉人潮，堪稱地表最大規模的人口移動\n     (D)南方近年降雨減少，旱象環生，南水北調將威脅南方用水的供應量\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-004", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "圖(一)是臺灣1958至2013年某種自然災害發布預警\n的各月總計次數分布圖，根據圖中各月的次數分\n布，該種自然災害的成因應為下列何者？", "options": ["板塊擠壓造成岩層變形或破裂", "熱帶洋面上低氣壓增強後侵襲", "冷、暖氣團交會形成鋒面滯留 (D)源自蒙古高氣壓區的氣團南下                        圖(一) 表(一)", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 4, "raw_text": "4.   圖(一)是臺灣1958至2013年某種自然災害發布預警\n     的各月總計次數分布圖，根據圖中各月的次數分\n     布，該種自然災害的成因應為下列何者？\n     (A)板塊擠壓造成岩層變形或破裂\n     (B)熱帶洋面上低氣壓增強後侵襲\n     (C)冷、暖氣團交會形成鋒面滯留\n     (D)源自蒙古高氣壓區的氣團南下                        圖(一)\n                                   表(一)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-005", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "世界主要宗教有基督教、佛              宗教信仰者\n教、印度教和伊斯蘭教。表                    甲       乙     丙     丁\n地區\n(一)為2010年上述各宗教的信   歐洲            25.7   2.7   0.1   0.3\n仰者在世界各地分布的百分       北美洲           12.3   0.2   0.2   0.8\n比，表中何者為穆斯林？        中南美洲          24.4   0.1 <0.1    0.1", "options": ["甲 撒哈拉以南非洲       23.8 15.5    0.2 <0.1", "乙 中東和北部非洲        0.6 19.8    0.2   0.1", "丙", "丁               亞洲及太平洋地區      13.2 61.7 99.3 98.7 合計           100.0 100.0 100.0 100.0 單位：%"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   世界主要宗教有基督教、佛              宗教信仰者\n     教、印度教和伊斯蘭教。表                    甲       乙     丙     丁\n                        地區\n     (一)為2010年上述各宗教的信   歐洲            25.7   2.7   0.1   0.3\n     仰者在世界各地分布的百分       北美洲           12.3   0.2   0.2   0.8\n     比，表中何者為穆斯林？        中南美洲          24.4   0.1 <0.1    0.1\n     (A)甲\n                        撒哈拉以南非洲       23.8 15.5    0.2 <0.1\n     (B)乙\n                        中東和北部非洲        0.6 19.8    0.2   0.1\n     (C)丙\n     (D)丁               亞洲及太平洋地區      13.2 61.7 99.3 98.7\n                        合計           100.0 100.0 100.0 100.0\n                                                   單位：%\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-006", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "鈞憶將圖(二)中的五張卡片分\n為圖(三)中的三類，其分類的\n依據最可能是下列何者？", "options": ["製作器物的技術", "文字發展的程度 (C)居住區域的位置             圖(二)            圖(三)", "", "使用貨幣的類型"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 6, "raw_text": "6.   鈞憶將圖(二)中的五張卡片分\n     為圖(三)中的三類，其分類的\n     依據最可能是下列何者？\n     (A)製作器物的技術\n     (B)文字發展的程度\n     (C)居住區域的位置             圖(二)            圖(三)\n     (D)使用貨幣的類型\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-007", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "圖(四)呈現某一時期中外交流概                       孽㓑岭䲘        䑄⚝\n況，下列何者符合該時期的往來\n情形？\n乃桪ⳛ◉", "options": ["雙方以紙幣作為交易的媒介                               㷠", "伊斯蘭教隨著商人傳入中國", "西方出口玉米、番薯等作物 (D)中國以絲綢為主要輸出商品                圖(四)", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 7, "raw_text": "7.   圖(四)呈現某一時期中外交流概                       孽㓑岭䲘        䑄⚝\n     況，下列何者符合該時期的往來\n     情形？\n                             乃桪ⳛ◉\n     (A)雙方以紙幣作為交易的媒介                               㷠\n     (B)伊斯蘭教隨著商人傳入中國\n     (C)西方出口玉米、番薯等作物\n     (D)中國以絲綢為主要輸出商品                圖(四)\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-008", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "圖(五)是呈現某古代文明政治運作特色的示意\n圖，此古文明最可能是下列何者？", "options": ["蘇美", "埃及", "雅典", "波斯 圖(五)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 8, "raw_text": "8.   圖(五)是呈現某古代文明政治運作特色的示意\n     圖，此古文明最可能是下列何者？\n     (A)蘇美\n     (B)埃及\n     (C)雅典\n     (D)波斯\n                                            圖(五)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-009", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "二十世紀初期，霍亂、瘧疾等傳染病在臺灣相當普遍，對當時政府而言，防治\n傳染病是刻不容緩的議題。下列何者最不可能是當時官方及民間採行的措施？", "options": ["政府實施全民健康保險", "公學校加強衛生教育課程", "保甲要求居民定期清潔環境", "警察協辦衛生及防疫宣導演講 表(二)"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 9, "raw_text": "9.   二十世紀初期，霍亂、瘧疾等傳染病在臺灣相當普遍，對當時政府而言，防治\n     傳染病是刻不容緩的議題。下列何者最不可能是當時官方及民間採行的措施？\n     (A)政府實施全民健康保險\n     (B)公學校加強衛生教育課程\n     (C)保甲要求居民定期清潔環境\n     (D)警察協辦衛生及防疫宣導演講\n\n                                    表(二)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-010", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "老師在課堂上用表(二)講解某      時間                 事件\n一主題，根據內容判斷，此主      1220年代 ★擊敗中亞的花剌子模\n★消滅金國\n題最可能是下列何者？", "options": ["清帝國的版圖拓展        1230年代 ★占領今日俄羅斯、烏克蘭等地", "阿拉伯勢力的發展 1240年代 ★攻入今日東歐地區", "鄂圖曼土耳其的擴張", "蒙古民族的對外征服"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 10, "raw_text": "10. 老師在課堂上用表(二)講解某      時間                 事件\n    一主題，根據內容判斷，此主      1220年代 ★擊敗中亞的花剌子模\n                                ★消滅金國\n    題最可能是下列何者？\n    (A)清帝國的版圖拓展        1230年代\n                                ★占領今日俄羅斯、烏克蘭等地\n    (B)阿拉伯勢力的發展\n                       1240年代 ★攻入今日東歐地區\n    (C)鄂圖曼土耳其的擴張\n    (D)蒙古民族的對外征服\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-011", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "曾被飼養的流浪動物對人類較無戒心，但此特點卻被某些人利用，他們不但\n虐待流浪貓、狗，還將過程拍成影片上傳到網路平臺供人觀賞。雖然違法者\n多已受到法律制裁，但憾事卻難以挽回。上述案例凸顯下列何者的重要性？", "options": ["辨識媒體傳播資訊的真偽", "生命無貴賤之分皆應被尊重", "資訊流通應避免侵害他人隱私", "重視環境保護以維護生物多樣性"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 曾被飼養的流浪動物對人類較無戒心，但此特點卻被某些人利用，他們不但\n    虐待流浪貓、狗，還將過程拍成影片上傳到網路平臺供人觀賞。雖然違法者\n    多已受到法律制裁，但憾事卻難以挽回。上述案例凸顯下列何者的重要性？\n    (A)辨識媒體傳播資訊的真偽   (B)生命無貴賤之分皆應被尊重\n    (C)資訊流通應避免侵害他人隱私 (D)重視環境保護以維護生物多樣性\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-012", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "下列是三位行政首長的發言內容：\n甲縣縣長：「感謝縣議會的支持，本縣領先全國引進熱氣球活動，創造商機。」\n乙市市長：「因應颱風來襲，為維護市民財產安全，本市今晚開放市區紅線停車。」\n丙縣縣長：「未來是否在本縣設置觀光賭場，我們將交由縣民以公投方式決定。」\n上述三位首長的發言內容，最足以彰顯下列何項概念？", "options": ["中央集權", "責任政治", "三權分立", "地方自治"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 下列是三位行政首長的發言內容：\n    甲縣縣長：「感謝縣議會的支持，本縣領先全國引進熱氣球活動，創造商機。」\n    乙市市長：「因應颱風來襲，為維護市民財產安全，本市今晚開放市區紅線停車。」\n    丙縣縣長：「未來是否在本縣設置觀光賭場，我們將交由縣民以公投方式決定。」\n    上述三位首長的發言內容，最足以彰顯下列何項概念？\n    (A)中央集權          (B)責任政治\n    (C)三權分立          (D)地方自治\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-013", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "圖(六)呈現出某項法律規定\n施行前、後，幸福社區公告\n內容的變化，根據圖中訊息\n判斷，該法律最可能是下列\n何者？", "options": ["《民法》", "《消費者保護法》", "《社會秩序維護法》", "《個人資料保護法》 圖(六)"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 13, "raw_text": "13. 圖(六)呈現出某項法律規定\n    施行前、後，幸福社區公告\n    內容的變化，根據圖中訊息\n    判斷，該法律最可能是下列\n    何者？\n    (A)《民法》\n    (B)《消費者保護法》\n    (C)《社會秩序維護法》\n    (D)《個人資料保護法》\n                           圖(六)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-society-014", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-107-society", "question_type": "single_choice", "question_text": "政府為因應失業問題，除了提供失業給付外，更積極協助失業者參與職業訓\n練，並提供就業資訊，以增加他們就業的機會。上述政府作為所要保障的人\n民基本權利類型，與下列何者最類似？", "options": ["接受國民教育提升國民素質", "組織政治團體表達民意訴求", "投票罷免失職民選公職人員", "遷移居住地至新工作地點旁"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "f2d1c3f41a4f", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 政府為因應失業問題，除了提供失業給付外，更積極協助失業者參與職業訓\n    練，並提供就業資訊，以增加他們就業的機會。上述政府作為所要保障的人\n    民基本權利類型，與下列何者最類似？\n    (A)接受國民教育提升國民素質\n    (B)組織政治團體表達民意訴求\n    (C)投票罷免失職民選公職人員\n    (D)遷移居住地至新工作地點旁\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
